import java.util.Scanner;

public class BufferOverflowExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.next(); // User inputs their name

        char[] buffer = new char[10]; // Buffer with fixed size of 10

        // Copy user input into the buffer without checking the length
        for (int i = 0; i < name.length(); i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Welcome, " + String.valueOf(buffer));
    }
}

