import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Use nextLine() to read entire line

        int bufferSize = 10;
        char[] buffer = new char[bufferSize]; // Buffer with fixed size

        // Copy user input into the buffer, ensuring it doesn't exceed the buffer size
        for (int i = 0; i < Math.min(name.length(), bufferSize); i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Welcome, " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
